1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: Cell[] = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = (x: number, y: number): string => `${x},${y}`;
10	
11	export const nextGeneration = (cells: Cell[]): Cell[] => {
12	  const aliveKeys = new Set(cells.map(([x, y]) => cellKey(x, y)));
13	
14	  const neighborsOf = ([x, y]: Cell): Cell[] =>
15	    NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
16	
17	  const isAlive = (cell: Cell): boolean => aliveKeys.has(cellKey(cell[0], cell[1]));
18	
19	  const countLiveNeighbors = (cell: Cell): number =>
20	    neighborsOf(cell).filter(isAlive).length;
21	
22	  const livesNextGeneration = (cell: Cell): boolean => {
23	    const count = countLiveNeighbors(cell);
24	    return count === 3 || (count === 2 && isAlive(cell));
25	  };
26	
27	  const candidates = new Map<string, Cell>();
28	  for (const cell of cells) {
29	    for (const candidate of [cell, ...neighborsOf(cell)]) {
30	      candidates.set(cellKey(candidate[0], candidate[1]), candidate);
31	    }
32	  }
33	
34	  return [...candidates.values()].filter(livesNextGeneration);
35	};
36

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("returns an empty array when given no living cells", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("kills a single isolated live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("kills two adjacent live cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("keeps a 2x2 block unchanged (still life)", () => {
15	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(input);
17	    expect(result).toHaveLength(4);
18	    expect(result).toEqual(expect.arrayContaining(input));
19	  });
20	  it("transforms a vertical blinker into a horizontal blinker", () => {
21	    const input: [number, number][] = [[0, 0], [0, 1], [0, 2]];
22	    const expected: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
23	    const result = nextGeneration(input);
24	    expect(result).toHaveLength(3);
25	    expect(result).toEqual(expect.arrayContaining(expected));
26	  });
27	  it("creates a new live cell when a dead cell has exactly 3 live neighbors (reproduction)", () => {
28	    const input: [number, number][] = [[0, 2], [1, 2], [0, 1]];
29	    const expected: [number, number][] = [[0, 2], [1, 2], [0, 1], [1, 1]];
30	    const result = nextGeneration(input);
31	    expect(result).toHaveLength(4);
32	    expect(result).toEqual(expect.arrayContaining(expected));
33	  });
34	  it.todo("kills a live cell with more than 3 live neighbors (overpopulation)");
35	  it.todo("handles negative coordinates correctly");
36	});
